def peryear(s):
    g=s.groupby(s.index.year)
    return ((g.last()/g.first()-1)*100).round(1)

P3={3:0.7}
def twbs(tw):
    return {st:{t:w*VALVE[st] for t,w in tw.items()} for st in (1,2,3,4,5)}
results={}
for name,stmap in [("NO_VALVE",None),("VALVE_R1",R1),("VALVE_R2",R2),("VALVE_HY",HY)]:
    bkw=mk_bkw(None)
    if stmap is not None: bkw["state_by_date"]=stmap
    ex_b={"tier_weights_by_state":twbs(TIER_WEIGHTS)} if stmap is not None else None
    ex_l={"tier_weights_by_state":twbs(LAG_TW)} if stmap is not None else None
    balB=runb(sig_mom_sup,TIER_BAL,f"BAL_{name}",TIER_WEIGHTS,bkw,extra=ex_b,park=P3)
    sb,tb,eb=addcap_v21(sig_mom_sup,balB,TIER_WEIGHTS,"B")
    eb2={**eb,**(ex_b or {})}
    balC=runb(sb,TIER_BAL+[t for t in tb if t.startswith("CAP")],f"BALc_{name}",tb,bkw,eb2,park=P3)
    lagB=runl(sig_lag,LAG_TW,f"LAG_{name}",bkw,extra=ex_l,park=P3)
    sl,tl,el=addcap_v21(sig_lag,lagB,LAG_TW,"L")
    el2={**el,**(ex_l or {})}
    lagC=runl(sl,tl,f"LAGc_{name}",bkw,el2,park=P3)
    s=(balC.set_index("time")["nav"]+lagC.set_index("time")["nav"].reindex(balC.set_index("time").index).ffill()).dropna()
    results[name]=s
    print(f"\n[{name}] override dates: {0 if ovr is None else len(ovr)}")
    report(name,s)

print("\n=== per-year (calendar) — host V2.3C ===")
tab=pd.DataFrame({k:peryear(v) for k,v in results.items()})
for k in results:
    if k!="NO_VALVE": tab[k+"-B"]=(tab[k]-tab["NO_VALVE"]).round(1)
